const ENGINE = $env.ENGINE_URL;
// The engine opens each measurement gate by ELAPSED TIME (MEASURE_AFTER_DAYS),
// so we just drain: /tick advances any job whose window has opened, through
// analytics -> optimizer -> learn. Jobs still inside their window stay put.
let steps = 0;
for (let i = 0; i < 500; i++) {
  const t = await this.helpers.httpRequest({ method: 'POST', url: ENGINE + '/tick', json: true });
  if (!t.advanced) break;
  steps++;
  await new Promise(r => setTimeout(r, 150));
}
const m = await this.helpers.httpRequest({ method: 'GET', url: ENGINE + '/jobs/measurable', json: true });
return [{ json: { drained: true, advanced_steps: steps, still_measurable: (m.jobs || []).length } }];
